#!/usr/bin/env node
// Guard against a stale or wrong-shape compiled contract.
//
// The compiled artifact (src/contract/managed/registry) is gitignored and is regenerated by
// `npm run compile:contract`. If the source contract is rewritten but not recompiled, the old
// binary silently lingers - and because publish.ts casts the contract to `any`, the web build
// still passes while loading the WRONG contract (this actually happened: a non-private build
// shadowed the privacy rewrite). This check asserts the compiled interface matches the
// privacy design encoded in src/contract/registry.compact, and fails the build loudly if not.
//
// Update the EXPECTED constants below if you intentionally change the contract interface.
import { readFileSync, existsSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const root = join(dirname(fileURLToPath(import.meta.url)), "..");
const infoPath = join(root, "src/contract/managed/registry/compiler/contract-info.json");

// The privacy design (see src/contract/registry.compact).
const EXPECTED = {
  witnesses: ["auditorSecret", "reportFingerprint"],
  circuit: { name: "publishReceipt", args: ["receiptId"] },
  ledger: ["ownerCommitment", "receipts", "published"],
};

function fail(msg) {
  console.error("\n✗ check-contract: " + msg);
  console.error(
    "\n  The compiled contract does not match the privacy design in " +
      "src/contract/registry.compact.\n  Recompile it:  npm run compile:contract  " +
      "(needs the Compact toolchain).\n",
  );
  process.exit(1);
}

if (!existsSync(infoPath)) {
  fail("contract not compiled (no contract-info.json found).");
}

let info;
try {
  info = JSON.parse(readFileSync(infoPath, "utf8"));
} catch (e) {
  fail("could not parse contract-info.json: " + e.message);
}

const witnesses = (info.witnesses ?? []).map((w) => w.name);
const ledger = (info.ledger ?? []).map((l) => l.name);
const circuit = (info.circuits ?? []).find((c) => c.name === EXPECTED.circuit.name);

const missingWitnesses = EXPECTED.witnesses.filter((w) => !witnesses.includes(w));
if (missingWitnesses.length) {
  fail(
    `missing witness(es) [${missingWitnesses.join(", ")}] - found [${witnesses.join(", ") || "none"}]. ` +
      "A witness-free contract is the old NON-PRIVATE build.",
  );
}

if (!circuit) {
  fail(`circuit '${EXPECTED.circuit.name}' not found (found: [${(info.circuits ?? []).map((c) => c.name).join(", ")}]).`);
}
const args = (circuit.arguments ?? []).map((a) => a.name);
if (args.length !== EXPECTED.circuit.args.length || !EXPECTED.circuit.args.every((a, i) => args[i] === a)) {
  fail(
    `${EXPECTED.circuit.name} args mismatch: expected [${EXPECTED.circuit.args.join(", ")}], got [${args.join(", ") || "none"}]. ` +
      "A public 'commitment' arg means the commitment is no longer derived from a private witness.",
  );
}

const missingLedger = EXPECTED.ledger.filter((l) => !ledger.includes(l));
if (missingLedger.length) {
  fail(`missing ledger field(s) [${missingLedger.join(", ")}] - found [${ledger.join(", ") || "none"}].`);
}

console.log(
  `✓ check-contract: privacy contract OK ` +
    `(compiler ${info["compiler-version"]}, witnesses [${witnesses.join(", ")}], ` +
    `${EXPECTED.circuit.name}(${args.join(", ")}), ledger [${ledger.join(", ")}]).`,
);
